var e=JSON.parse(`[{"id":"L2_1","type":"narration","speaker":null,"text":{"KOREA":"근무 시간 내내 사무실 공기에 날이 서 있다.","JPN":"勤務時間中、事務室の雰囲気はピリピリしている。","ENG":"The workplace atmosphere is on edge throughout the day.","TWN":"上班時間辦公室內總是充斥著緊張的氣氛。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"이봐요, 출근 시간 딱 맞춰서 회사를 나오면 어떡합니까?","JPN":"君～、始業時間ピッタリに出勤してどうするんだ？","ENG":"Hey, who comes into the office at exactly 9 o'clock, huh?","TWN":"我說你，哪有人幾點上班就真的幾點到公司的？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"경력이 쌓였으면 모범을 보여야지. 회사가 놀러다니는 곳이야?","JPN":"キャリアを積んだら手本を示してくれないと。会社は遊び場じゃないんだぞ。","ENG":"You've been here long enough to set an example to others. Do you think this is a place where you can come and go as you please?","TWN":"你在公司的時間也不短，要有點榜樣吧？公司是玩樂的地方嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"아니, 누가 차 끌고 다니랬어요?","JPN":"誰も車出勤を強要してないだろう？","ENG":"Hey, it's not my fault you brought your car to work.","TWN":"拜託，是有人逼你開車上班嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAFF_NPC_NULL_NULL","text":{"KOREA":"변명은 됐고 이따 나랑 얘기 좀 해요. 지금은 내가 좀 바빠서.","JPN":"言い訳はいいから後でちょっと来たまえ。今は忙しいから。","ENG":"Enough with the excuses. We'll talk more about it  later. I'm busy right now.","TWN":"少在那邊找藉口，待會兒跟我談一下，我現在有點忙。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAFF_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"narration","speaker":null,"text":{"KOREA":"아끼던 골프채가 부서졌나? 아침부터 아내와 다퉜나?","JPN":"大事にしていたゴルフクラブが折れたのか？　それとも朝から奥さんとケンカしたのか？","ENG":"Did his precious golf club break? Or did he have a fight with his wife this morning?","TWN":"心愛的高爾夫球桿斷掉嗎？一早就和太太吵架嗎？"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"narration","speaker":null,"text":{"KOREA":"상사가 예민한 날에는 항상 구실이 있다. 나와 아무런 관계도 없고, 내가 어찌할 수도 없는 구실이.","JPN":"上司がイラ立っている日にはいつも口実がある。僕とはなんの関係もなく、僕がどうすることもできない口実が。","ENG":"There's always some type of rant on days when he's not in a good mood. It has nothing to do with me, but there's nothing I can do about it as well.","TWN":"主管在尷尬的時刻總是會有藉口，那些和我一點關係也沒有，我也無可奈何的藉口。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"narration","speaker":null,"text":{"KOREA":"칸막이를 친 책상이 묫자리처럼 을씨년스럽다.","JPN":"パーティションに囲まれた席が墓場のようにうすら寒い。","ENG":"Man, sitting inside this cubicle makes me feel like I'm suffocating...","TWN":"設有隔板的辦公桌就像墳墓般淒涼。"},"stage":{"bg":"OFFICE_NORMAL","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의, 의장님! 언제 오셨어요?","JPN":"ぎ、議長！　いついらっしゃったのですか？","ENG":"M-Mr. Chairman! You've arrived early!","TWN":"議…議長！您是什麼時候來的？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"미리 말씀이라도 해 주시지. 그럼 저희가 편안히 모셨을 텐데요.","JPN":"事前におっしゃってくだされば、私たちがちゃんとお迎えしましたのに。","ENG":"You should've called, then I would've sent a car for you.","TWN":"怎麼沒先說一聲呢？這樣我們才好接待您的嘛。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 사업으로 바쁠 텐데 유난 떨 것 없지.","JPN":"はは、事業で忙しいだろう、無駄な気遣いは不要だ。","ENG":"Haha. I'm sure you're busy, running this place and all.","TWN":"呵呵，你們應該都忙著在做生意吧，無需格外對我費心。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"헤이븐은 어디 있나?","JPN":"ヘイブンはどこだ？","ENG":"Speaking of, where is Haven?","TWN":"天堂呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"헤이븐 님은…… 지금 부재 중이셔요.","JPN":"ヘイブン様は……ただいま留守にしております。","ENG":"Mr. Haven is... busy right now.","TWN":"天堂先生……目前不在。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"흠. 아쉽게 됐군. 그럼 이야기는 다음 기회로 미뤄야겠어.","JPN":"ふむ。残念だな。それでは話はまた今度にしよう。","ENG":"Hmm... That's a shame. Then perhaps I should come another day.","TWN":"嗯，真可惜，那就下次再談囉。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아앗! 의장님. 잠시, 잠시만요!","JPN":"ああっ！　議長。ちょっと、ちょっとお待ちを！","ENG":"Oh! Mr. Chairman, please wait!","TWN":"那個！議長，請先稍等一下！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"음? 뭔가?","JPN":"うむ？　何だ？","ENG":"Hmm? What is it?","TWN":"嗯？什麼事？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"여기까지 오셨는데 저희에게 대접할 기회는 주셔야죠.","JPN":"ここまでご足労くださったのですから、おもてなしをするチャンスくらいはください。","ENG":"But you came all this way. Please allow me to at least make it up to you.","TWN":"您大駕光臨，總得給我們個機會招待您吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아… 떨려. 제가 평소부터 얼마나 의장님을 존경해 왔는지 모르실 겁니다.","JPN":"はあ……緊張するわ。私が普段からどれほど議長を尊敬してきたことか。","ENG":"*Sigh...* I'm so nervous right now. You have no idea how much I have always admired you.","TWN":"呼…好緊張，議長您應該不知道我平時有多尊敬您吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 혹시 <color=#ffd34c>기생체</color>라고 들어보셨나요?","JPN":"あ！　もしかして<color=#ffd34c>寄生体</color>をご存じですか？","ENG":"Oh! Mr. Chairman, have you ever heard of a <color=#ffd34c>parasite</color>?","TWN":"請問！您聽說過<color=#ffd34c>寄生物</color>嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"영생의 비결이라고 알려진 그것이 곧 제 손 안에 들어온답니다.","JPN":"永生の秘訣として知られているそれが、もうすぐ手に入ります。","ENG":"That which is known as the key to eternal life will soon be within my grasp.","TWN":"據說它可以長生不老，而它很快就會落到我手裡。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제 발로 여기 걸어 들어오게 확실한 수를 써 뒀죠. 의장님께 선물로 드리기 위해서요.","JPN":"自分の足でここに来るように確実に手を打っておきましたの。議長に差し上げるために。","ENG":"I made sure that it will sneak into this ship so I can give it to you as a gift, Mr. Chairman.","TWN":"我有設下可以讓它自己送上門的圈套，這是要送給議長的禮物。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 확실한 수라. 꼭 갬블러처럼 말하는군.","JPN":"はは、確実に手を打ったなんて。ギャンブラーのようなことを言うな。","ENG":"Haha! \\"Made sure\\", eh? You sound just like Gambler.","TWN":"呵呵，圈套嗎？說話的方式和賭徒一樣呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"후훗. 의원 분과 비교해 주시다니 영광입니다. 역시 안목이 남다르세요.","JPN":"ふふっ。議員の方に例えていただけて光栄ですわ。さすが見る目が違いますね。","ENG":"Fu fu. I'm flattered that you compare me with a Council member. You have a good eye for people, Mr. Chairman.","TWN":"呵呵，能夠與議員相提並論是我的榮幸，您的眼光果然是與眾不同呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"제 보스는 할일도 내팽개치고 놀러 다니기 바빠서……","JPN":"私のボスは仕事も放り出して遊びに夢中で……","ENG":"However, my boss is always so busy playing around that he never does any of the work...","TWN":"哪像我的老闆都不務正業，光顧著玩……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"헤이븐이 자리를 비운 게 놀기 위해서였나.","JPN":"ヘイブンが留守なのは遊ぶためだったか。","ENG":"Haven's not here because he's too busy playing, you say?","TWN":"天堂不在是因為去玩嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"아! 저도 모르게 상사 험담을 하고 말았군요. 추태를 보여 죄송합니다.","JPN":"まあ！　つい上司の悪口を言ってしまいましたね。醜態をお見せして申し訳ございません。","ENG":"Oh! My apologies. That was rude of me to bad-mouth my boss in front of you.","TWN":"哎呀！我竟然脫口說出老闆壞話，抱歉我失態了。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"아니야. 헤이븐이 가벼운 사람이라는 건 알고 있었으니까.","JPN":"いや。ヘイブンが軽い人間だということは知っている。","ENG":"Not at all. I knew Haven wasn't a serious person.","TWN":"沒事，我本來就知道天堂並非可靠之人。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"게다가 자네와는 특히 가까운 사이 아닌가?","JPN":"しかも、君とは特に近い仲だろう？","ENG":"You two are close to each other, aren't you?","TWN":"而且他和你的關係很親近不是嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"역시 이미 꿰뚫어보고 계셨군요.","JPN":"やはりすでに見抜いてらっしゃったんですね。","ENG":"As expected, I see you already know.","TWN":"原來您早就知道嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"워낙 자주 일을 떠맡기고 자리를 비우시는 바람에, 저는 매일 밤 잠도 못 이룬답니다.","JPN":"よく仕事を押しつけて留守にするせいで、毎晩まともに眠ることもできませんの。","ENG":"He always leaves me to do so much work that I'm sleep-deprived most days.","TWN":"他老是把事情扔給我，然後自己不見人影，搞得我每天都沒辦法睡覺。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"수면 부족으로 다크 서클까지 이렇게 짙어졌지 뭐예요. 속상하게.","JPN":"睡眠不足でダークサークルがこんなにも酷くなってしまって。悲しいわ。","ENG":"Do you see the bags under my eyes? I get so little sleep they just keep getting darker every day.","TWN":"睡眠不足害我的黑眼圈變這麼深，我真委屈。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"쪽잠이라도 자려고 해도 최근에는 스트레스 때문인지 악몽까지 꾸게 되어서요.","JPN":"少しでも眠ろうとするのですが、最近はストレスのせいか悪夢まで見るようになってしまって。","ENG":"Even if I try to take a nap, all the stress is giving me nightmares.","TWN":"想說要瞇一下，結果最近因為壓力太大，甚至還會做惡夢。"},"stage":{"bg":"DREAM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님처럼 훌륭하신 분 밑에서 일하면 잠을 설칠 일은 없을 텐데 말이에요.","JPN":"議長のように立派な方の下で働ければ、眠れないなんてことはないはずですのに。","ENG":"If only I could work under someone as brilliant as you, then I would be able to sleep like a baby at night.","TWN":"要是能在像議長這麼優秀的人手下做事，應該就不會有睡眠不足的問題吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"악몽이라…… 자네는 악인에 속하니 흉신의 장난일지도 모르겠군.","JPN":"悪夢か……君は悪人だから、凶神のいたずらかもしれないな。","ENG":"Nightmares, you say? Perhaps that is a prank by one of the Fiends. You are a villain after all.","TWN":"做惡夢嗎……可能因為你是壞人，才會被凶神惡作劇吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"흉신이라니요?","JPN":"凶神ですって？","ENG":"A Fiend?","TWN":"凶神？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"세상이 번영을 허락하지 않았음에도 떠나야 할 때를 놓치고 남은 자들이지.","JPN":"この世が繁栄を許していないのにもかかわらず、去る時を逃して残っている者たちのことだ。","ENG":"They are beings who missed their opportunity to leave and have remained on this earth, deprived of prosperity.","TWN":"雖然世界不歡迎他們，但他們因為錯過離開的時機而留下。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"동족들과 함께 멸종하지도 못하고, 그들의 후손들처럼 적응하지도 못한 채로.","JPN":"同族と共に絶滅することもできず、彼らの末裔のように適応することもできないままにね。","ENG":"They live, unable to go extinct with their own kind or adapt like their descendants.","TWN":"無法和同族一起滅亡，也無法像他們的後裔那般適應。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"혹시 밤에 자줏빛 불꽃을 본 적이 있다면 잠시만 참게나. 그녀가 다시 거둬 가 줄 테니.","JPN":"夜に紫色の炎を見たことがあるならもうしばらく我慢するといい。彼女がまた取り込んでいってくれるはずだから。","ENG":"If you've ever seen violet flame at night, hold on just a little longer. She will come to retrieve it.","TWN":"若你曾在晚上看到紫色火球，就稍微忍耐一下吧，她會再來收回的。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님, 농담치고는 조금…… 아니, 매우 독특하네요.","JPN":"議長、冗談にしてはちょっと……いや、とても独特ですわね。","ENG":"Mr. Chairman, sir... Your jokes are... rather unique, to say the least.","TWN":"議長，您的笑話……還真特別呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"말씀하신 자줏빛 불꽃을 본 적은 있지만, 그냥 어디에나 있을 법한 카운터의 능력이었어요.","JPN":"おっしゃった紫色の炎を見たことはありますけど、別にどこにでもありそうなカウンターの能力でしたわ。","ENG":"Yes, I have seen the purple flames before, but... that's just any Counter's ability, is it not?","TWN":"我是曾經看到您說的紫色火球沒錯，但那應該只是很普通的制裁者技能吧。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님께서 조금 오해하신 것 아닐까요? 소문이라는 건 부풀려지기 마련이니까요.","JPN":"議長が少々誤解なさっているのではないですか？　噂というものは大きくなるものですから。","ENG":"Perhaps you are mistaken, Mr. Chairman? Rumors tend to grow bigger as they spread.","TWN":"議長是不是太當真啦？流言多少都會有加油添醋的成分在。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"하하, 나에게 그렇게 말하는 사람은 오랜만이야. 생각보다 재밌군, 자네.","JPN":"はは、私にそんな風に言う人は久しぶりだ。意外と面白いんだな、君は。","ENG":"Haha. It's been a long time since anyone has said something like that to me. You're a more interesting character than I thought.","TWN":"呵呵，很久沒人敢這麼跟我說話，你比我想像中還有趣呢。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님께서 짐작도 못하실 재밌는 일들을 잔뜩 알고 있으니 언제든 불러 주세요.","JPN":"議長には想像もつかないような面白い話をたくさん存じておりますから、いつでもお呼びください。","ENG":"Well, I'm sure I know a lot more interesting things than you can imagine. So please, call me whenever you want to hear them.","TWN":"我還知道很多議長想像不到的趣事呢，歡迎您常找我。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"언제가 됐든 달려갈 수 있도록 준비해 둘게요.","JPN":"いつでも駆けつけられるように準備しておきますわ。","ENG":"I'll be ready to go whenever you call for me.","TWN":"無論是白天或夜晚，只要您一句話我就會立刻飛奔過去。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"그래. 기대하지.","JPN":"そうか。楽しみにしておこう。","ENG":"All right. I shall.","TWN":"好，我很期待。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_NIGHTMARE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SYSOP_EP9HALF_NULL_NULL","text":{"KOREA":"혹시 숙소를 준비해 줄 수 있겠나? 여기서 타로 점을 보기로 했거든.","JPN":"ところで部屋を用意してもらえないか？　ここでタロット占いをしてもらうことになっているんだ。","ENG":"Could you get me a room for the night? I'm supposed to have my fortune read right after.","TWN":"你可以幫我安排一下住宿嗎？我打算在這算塔羅牌。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYSOP_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"당연하죠. 전망이 가장 좋은 곳으로 준비해 드리겠습니다.","JPN":"もちろんです。一番展望のいいところにご用意します。","ENG":"Of course. I'll get you the room with the best view.","TWN":"沒問題，我會替您安排一個景色絕佳的地方。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"쯧. 애송이 주제에 영 귀여운 구석이 없어. 살살 치켜세워 주면 넘어올 줄 알았더니.","JPN":"ちっ。ガキのくせに可愛くないわね。ちょっとおだてれば乗ってくると思ったのに。","ENG":"Tch! Little runt, he's not cute at all. I thought appeasing him would win him over...","TWN":"嘖，明明就是個小鬼，卻一點也不可愛。我還以為我只要稍微勾勾手他就會上鉤呢。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"타로 점은 무슨. 흉신이니 뭐니, 어디서 이상한 소리를 주워듣고 와서는…….","JPN":"それにタロット占いって何？　凶神だのなんだの、どこから変な噂を聞いてきては……","ENG":"And what's all this nonsense about fortune and Fiends...?","TWN":"什麼塔羅牌，什麼凶神的，從哪聽來這些莫名其妙的東西……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"헤론 님. 말씀드릴 것이 있습니다.","JPN":"ヘロン様。お伝えすることがあります。","ENG":"Madam Heron. There's something you should know.","TWN":"海倫夫人，有事要向您報告。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"의장님께서 다시 돌아오셨나요? 아니면 헤이븐 님을 찾은 건가?","JPN":"議長がお戻りになったの？　それともヘイブン様が見つかったの？","ENG":"Did the Chairman come back? Or did you find Haven?","TWN":"議長又回來了嗎？還是找到天堂了？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"둘 다 아닙니다만, 중요한 사항입니다.","JPN":"両方とも違いますが、重要なことです。","ENG":"No, Madam. But it's an important matter.","TWN":"都不是，是很重要的事。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"지금 그 둘 말고 더 중요한 게 어딨어!","JPN":"今それ以外に重要なことはないわ！","ENG":"WHAT COULD BE MORE IMPORTANT THAN THAT?!","TWN":"現在還有什麼比他們二個更重要的嗎！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"내가 혼자 의장님 상대하느라 고생하는 동안 그거 하나 못 찾고 뭐하는 거야?!","JPN":"私が一人で議長の相手をしてる間にヘイブンのひとりも探せないなんて、何してるの！？","ENG":"While I'm here dealing with the Chairman alone, you can't even find Haven?!","TWN":"在我獨自辛苦面對議長的時候，你卻連這點小事也辦不好嗎？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"오즈 일당이 헤이븐 랜드에 들어왔습니다.","JPN":"オズの連中がヘイブンランドに来ています。","ENG":"The OZ kids are here at Havenland.","TWN":"奧茲國的人現在在天堂樂園裡。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"뭐라고? 그 꼬맹이들이?","JPN":"は？　あのガキどもが？","ENG":"What? Those little brats?","TWN":"你說什麼？那些小鬼？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"네. 라스트 헤이븐에서 허드슨을 상대로 도전에 성공했다더군요.","JPN":"はい。ラストヘイブンでハドソン相手に挑戦して成功したらしいです。","ENG":"Yes. They have also managed to win the challenge against Hudson in Last Haven.","TWN":"是的，而且他們還在最後的天堂成功挑戰哈德森。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그 꼬맹이들이 한가하게 이벤트에나 참가하고 있었다고?","JPN":"あのガキどもがのんきにイベントに参加してたですって？","ENG":"Wait, they're here to do some stupid event?","TWN":"那些小鬼還有閒情逸致參加活動？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"찾았으면 왜 가만 놔두는 거야?!","JPN":"見つけたならなんで何の処置もしないの！？","ENG":"Well, if you found them, why aren't you doing anything about it?!","TWN":"既然有找到人，那你們為何沒有任何行動？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"<color=#ffd34c>독사과</color>는 제대로 작동하고 있잖아! 썩 해치워 버려!","JPN":"<color=#ffd34c>毒リンゴ</color>はちゃんと作動してるでしょ！　早く処理しなさい！","ENG":"<color=#ffd34c>Poison Apple</color> works just fine! Get rid of them!","TWN":"<color=#ffd34c>毒蘋果</color>不是還有在正常運作嗎！把她們全都給我幹掉！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"당장은 어렵습니다.","JPN":"今すぐは無理です。","ENG":"It has proven to be difficult at the moment.","TWN":"目前有點困難。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"오랜만에 도전을 성공한 자들이라 지켜보는 눈이 많습니다.","JPN":"久々の挑戦成功者なので、周囲の目が多すぎます。","ENG":"It has been a long time since anyone won a challenge. There were too many eyes watching.","TWN":"因為時隔許久才有人挑戰成功，現在大家的目光都在她們身上。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"무력을 사용하면 도전을 막으려는 수작으로 보이지 않겠습니까.","JPN":"武力を使えば挑戦をやめさせようとしていると見られる可能性があります。","ENG":"Using force in that moment would make everyone think that it was rigged.","TWN":"要是動用武力，群眾會不會認為我們是想搞小動作阻止她們贏呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"형님의 이미지 손상, 나아가 헤이븐 랜드의 수익성에도 악영향을 끼치겠죠.","JPN":"兄貴のイメージに傷がつき、ひいてはヘイブンランドの収益にも悪影響が出かねません。","ENG":"That would damage Mr. Haven's image, as well as the profitability of Havenland.","TWN":"這樣不僅有損大哥的形象，甚至也會影響到天堂樂園的收入。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"그것도 그렇겠네…….","JPN":"それもそうね……","ENG":"I guess that's true...","TWN":"你說的也有道理……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"하아. 그럼 이렇게 하죠.","JPN":"はあ。じゃあ、こうしましょう。","ENG":"*Sigh...* Then this is what we'll do.","TWN":"哀，那就這麼做吧。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"놈들이 도전자 노릇을 하고 있다면, 도전 중에 뭉개 버리세요.","JPN":"やつらが挑戦者のふりをしてるのなら、挑戦中に潰しなさい。","ENG":"If these brats want to keep playing as the challenger, then we'll crush them while they're at it.","TWN":"既然他們現在是挑戰者的身分，那就在挑戰的過程中毀掉她們吧！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"HERON_NPC_HAVEN_NULL","text":{"KOREA":"저능한 얼간이들이 이벤트에서 사고를 치는 건 저희 책임이 아니잖아요?","JPN":"能力のない間抜けがイベントで事故を起こしたとしても、私たちの責任じゃないでしょう？","ENG":"It's not our responsibility if these idiots get into an accident while doing the event, right?","TWN":"那些低能的小鬼在活動上闖禍的話，應該就不能算是我們的責任吧？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERON_NPC_HAVEN_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"이해했습니다. 말씀하신 대로 처리하죠.","JPN":"了解しました。おっしゃったように処理します。","ENG":"Understood. I will proceed as you wish.","TWN":"好的，就照夫人的吩咐處理。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"후우.","JPN":"ふぅ。","ENG":"*Sigh*","TWN":"呼。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"또 헤론 님이 난동을 피우시나?","JPN":"またヘロン様が暴れてるのか？","ENG":"Madam Heron making a fuss again?","TWN":"海倫夫人又打算胡來是嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"그래. 잠을 못 주무셔서 그런지 히스테리가 잦으시군.","JPN":"ああ。眠れないからか、ヒステリーが酷い。","ENG":"Yeah. She's getting more hysterical. Maybe it's due to her lack of sleep.","TWN":"嗯嗯，不知道是不是因為她最近常失眠，變得很易怒。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"하하, 비위 맞추느라 고생이 많아.","JPN":"はは、機嫌どり、ご苦労だな。","ENG":"Haha! You did well sucking up to her rants.","TWN":"哈哈，辛苦你還要配合她。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"누군가는 맡아야 할 일이야. 형님과 가장 가까운 분이시니까.","JPN":"誰かはやるべきことだ。兄貴にもっとも近い方だからな。","ENG":"Someone has got to do it. She's the closest person to Mr. Haven.","TWN":"總得要有人來承擔吧，誰叫她和大哥的關係那麼好。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"아이들은 드림 네버 랜드로 갔다고 했던가?","JPN":"子どもたちはドリームネバーランドに向かったと言ったか？","ENG":"Did you say the kids went to Dream Neverland?","TWN":"你說她們去了夢幻樂園嗎？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"어이, 휴스턴.","JPN":"おい、ヒューストン。","ENG":"Hey, Huston.","TWN":"喂，休士頓。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"무슨 일이지?","JPN":"どうした？","ENG":"Yes?","TWN":"什麼事？"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DANCE_NPC_HAVEN_NULL","text":{"KOREA":"아직 새파랗게 어린 애들이야. 살살해.","JPN":"まだ尻の青い子どもだ。加減してやれ。","ENG":"They're just kids. Go easy on them.","TWN":"她們還只是孩子，下手輕一點。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DANCE_NPC_HAVEN_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PARK_NPC_HAVEN_NULL","text":{"KOREA":"……노력해 보지.","JPN":"……努力しよう。","ENG":"...I'll do my best.","TWN":"……我盡量。"},"stage":{"bg":"CORRIDOR_05","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PARK_NPC_HAVEN_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};